body:
For unpacked arrays, `vpi_handle(vpiLeftRange, array_hdl)` always returns the higher value, no matter if the **msb** is greater or less than the **lsb**. `vpi_handle(vpiRightRange, array_hdl)` always returns the lower value.

This modified **t_vpi_var** test fails:
```diff
diff --git a/test_regress/t/t_vpi_var.cpp b/test_regress/t/t_vpi_var.cpp
index f49e4b16..3da9a3d0 100644
--- a/test_regress/t/t_vpi_var.cpp
+++ b/test_regress/t/t_vpi_var.cpp
@@ -311,6 +311,25 @@ int _mon_check_var() {
         CHECK_RESULT_CSTR(p, "vpiConstant");
     }

+    TestVpiHandle vh5 = VPI_HANDLE("quads");
+    CHECK_RESULT_NZ(vh5);
+    {
+        TestVpiHandle vh10 = vpi_handle(vpiLeftRange, vh5);
+        CHECK_RESULT_NZ(vh10);
+        vpi_get_value(vh10, &tmpValue);
+        CHECK_RESULT(tmpValue.value.integer, 2);
+        p = vpi_get_str(vpiType, vh10);
+        CHECK_RESULT_CSTR(p, "vpiConstant");
+    }
+    {
+        TestVpiHandle vh10 = vpi_handle(vpiRightRange, vh5);
+        CHECK_RESULT_NZ(vh10);
+        vpi_get_value(vh10, &tmpValue);
+        CHECK_RESULT(tmpValue.value.integer, 3);
+        p = vpi_get_str(vpiType, vh10);
+        CHECK_RESULT_CSTR(p, "vpiConstant");
+    }
+
     return 0;
 }

diff --git a/test_regress/t/t_vpi_var.v b/test_regress/t/t_vpi_var.v
index 34b94b34..fc7d3b81 100644
--- a/test_regress/t/t_vpi_var.v
+++ b/test_regress/t/t_vpi_var.v
@@ -29,7 +29,7 @@ extern "C" int mon_check();
    reg [2:1]   twoone          /*verilator public_flat_rw @(posedge clk) */;
    reg [2:1]   fourthreetwoone[4:3] /*verilator public_flat_rw @(posedge clk) */;

-   reg [61:0]  quads[3:2]      /*verilator public_flat_rw @(posedge clk) */;
+   reg [61:0]  quads[2:3]      /*verilator public_flat_rw @(posedge clk) */;

    reg [31:0]     count        /*verilator public_flat_rd */;
    reg [31:0]     half_count   /*verilator public_flat_rd */;
```

